# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transaction(transactions, accounts):
    for transaction in transactions:
        from_account = transaction['from_account']
        to_account = transaction['to_account']
        amount = transaction['amount']

        if from_account in accounts and to_account in accounts and accounts[from_account] >= amount:
            accounts[from_account] -= amount
            accounts[to_account] += amount
            print(f"Transaction Successful: {amount} transferred from {from_account} to {to_account}")
        else:
            print(f"Transaction Failed: Cannot transfer {amount} from {from_account} to {to_account}")
    return accounts

# Example usage:
accounts = {'account1': 5000, 'account2': 3000, 'account3': 7000}
transactions = [
    {'from_account': 'account1', 'to_account': 'account2', 'amount': 1500},
    {'from_account': 'account3', 'to_account': 'account1', 'amount': 2000},
    {'from_account': 'account2', 'to_account': 'account3', 'amount': 5000}
]

updated_accounts = process_transaction(transactions, accounts)
print(updated_accounts)